protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexing is managed via the container's indexing policy,
    // not EF Core. HasIndex now throws at startup in EF Core 9.

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use the old name, and direct SQL queries reference c.Discriminator.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id generation from "Product|123" to just "123".
        // Existing documents use the compound format; without this, FindAsync and
        // point-reads will fail against existing data.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

